#include<bits/stdc++.h>
using namespace std;
vector<int> e[100001];
int n, maxx;
int a[100001];
int v[100001];
int dfs(int x) {
	if (v[x] != 0) return v[x];
	int ans = 0;
	for (int i = 0; i < e[x].size(); i++) {
		ans += dfs(e[x][i]);

	}
	ans += 1;
    v[x]=ans;
	return ans;
}
int main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
	}
	for (int i = 1; i <= n - 1; i++) {
		int x, y;
		cin >> x >> y;
		if (a[x] > a[y]) e[x].push_back(y);
		else e[y].push_back(x);
	}
	for (int i = 1; i <= n; i++) {
		maxx=max(maxx,dfs(i));
	}
	cout<<maxx;
	return 0;
}
